import React, { useRef, useState, useEffect, useMemo } from "react";
import data from "../../data/portfolio.json";

const { temas, tags, usos } = data.dicts;

function useClickOutside(ref, callback) {
  useEffect(() => {
    const handle = (e) => {
      if (ref.current && !ref.current.contains(e.target)) callback();
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [ref, callback]);
}

export default function FilterPanel({
  activeFilters,
  setActiveFilters,
  filteredCount,
}) {
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [openGroup, setOpenGroup] = useState(null);
  const filtersRef = useRef(null);

  useClickOutside(filtersRef, () => {
    // Solo cerramos si el clic fue fuera de TODO el panel (botón + acordeón)
    setFiltersOpen(false);
  });

  const groups = useMemo(
    () => [
      { label: "Temas", items: temas },
      { label: "Tags", items: tags },
      { label: "Usos", items: usos },
    ],
    []
  );

  const toggleFilter = (filter) => {
    setActiveFilters((prev) =>
      prev.includes(filter)
        ? prev.filter((f) => f !== filter)
        : [...prev, filter]
    );
    // NO cerramos filtersOpen
  };

  return (
    <div
      style={{
  background: "#ffffff",
  padding: "14px 24px",
  borderBottom: "1px solid #e5e5e5",
}}
    >
      <div
        style={{
          display: "flex",
          alignItems: "flex-start", // ← cambiado de "center" a "flex-start"
          gap: "12px",
        }}
      >
        {/* RESULTADOS */}
        <div
          style={{
  fontSize: "14px",
  color: "#5c5c5c",
  whiteSpace: "nowrap",
  paddingTop: "10px",
}}
        >
          {filteredCount} resultado{filteredCount === 1 ? "" : "s"}
        </div>

        {/* CONTENEDOR PRINCIPAL (BOTÓN + ACORDEÓN) */}
        <div ref={filtersRef} style={{ flex: 1, maxWidth: "700px", position: "relative" }}>
          {/* BOTÓN FILTRAR */}
          <button
            type="button"
            onClick={() => setFiltersOpen((v) => !v)}
            style={{
  width: "100%",
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  padding: "10px 14px",
  borderRadius: "999px",
  border: "1px solid #e5e5e5",
  background: "#ffffff",
  cursor: "pointer",
  fontFamily: "'Montserrat', sans-serif",
  fontSize: "13px",
  color: "#5c5c5c",
}}
          >
            {/* IZQUIERDA: chips o texto */}
            <span style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
              {activeFilters.length === 0 ? (
                <span style={{ color: "#aaa" }}>Filtrar</span>
              ) : (
                activeFilters.map((filter) => (
                  <span
                    key={filter}
                    onClick={(e) => {
                      e.stopPropagation();
                      setActiveFilters((prev) =>
                        prev.filter((f) => f !== filter)
                      );
                    }}
                    style={{
                      display: "inline-flex",
                      alignItems: "center",
                      gap: "6px",
                      padding: "4px 10px",
                      borderRadius: "999px",
                      border: "1px solid #ccc",
                      background: "#fff",
                      fontSize: "12px",
                      cursor: "pointer",
                    }}
                  >
                    {filter}
                    <span style={{ fontSize: "11px", color: "#888" }}>✕</span>
                  </span>
                ))
              )}
            </span>

            {/* DERECHA: X global */}
            {activeFilters.length > 0 && (
              <span
                onClick={(e) => {
                  e.stopPropagation();
                  setActiveFilters([]);
                }}
                onMouseEnter={(e) => (e.currentTarget.style.color = "#000")}
                onMouseLeave={(e) => (e.currentTarget.style.color = "#888")}
                style={{
                  marginLeft: "10px",
                  fontSize: "14px",
                  color: "#888",
                  cursor: "pointer",
                  flexShrink: 0,
                }}
              >
                ✕
              </span>
            )}
          </button>

          {/* ACORDEÓN DE GRUPOS (AHORA DENTRO DEL REF) */}
          <div
  style={{
    position: "absolute",
  top: "100%",
  left: 0,
  right: 0,
  zIndex: 20,
  marginTop: "8px",
  padding: filtersOpen ? "14px 18px" : "0 18px",
  border: filtersOpen ? "1px solid #e5e5e5" : "none",
  borderRadius: "14px",
  background: filtersOpen ? "#ffffff" : "transparent",
  boxShadow: filtersOpen ? "0 8px 24px rgba(0,0,0,0.1)" : "none",
    display: "flex",
    flexWrap: "wrap",
    gap: "24px",           // ← más separación entre grupos
    width: "100%",
    maxHeight: filtersOpen ? "400px" : "0px",
    overflowY: "auto",     // ← scroll si hay muchos items
    overflowX: "hidden",
    opacity: filtersOpen ? 1 : 0,
    transition:
      "max-height 0.3s ease, opacity 0.2s ease, padding 0.2s ease",
  }}
>
            {groups.map((group) => {
              const isOpen = openGroup === group.label;
              return (
                <div
                  key={group.label}
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    minWidth: "180px",
                  }}
                >
                  <div
                    onClick={() => setOpenGroup(isOpen ? null : group.label)}
                    style={{
  cursor: "pointer",
  fontWeight: "bold",
  fontSize: "14px",
  marginBottom: "6px",
  color: "#1e3a5f",
}}
                  >
                    {group.label}
                  </div>
                  {isOpen && (
                    <div style={{ paddingLeft: "8px" }}>
                      {group.items.map((filter) => {
                        const active = activeFilters.includes(filter);
                        return (
                          <div
                            key={filter}
                            onClick={() => toggleFilter(filter)}
                            role="button"
                            tabIndex={0}
                            onKeyDown={(e) => {
                              if (e.key === "Enter" || e.key === " ") {
                                e.preventDefault();
                                toggleFilter(filter);
                              }
                            }}
                            style={{
                              cursor: "pointer",
                              fontSize: "13px",
                              color: active ? "#7b5ea7" : "#777",
                              padding: "3px 0",
                              fontFamily: "'Montserrat', sans-serif",
                            }}
                          >
                            {filter}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
